interface ManufacturerShipmentData {
  order_number: string
  recipient_name: string
  phone: string
  address: string
  product_name: string
  quantity: number
  tracking_no: string
  request_note: string
  date_from_excel?: string // 엑셀의 날짜 컬럼
}

interface DailyStats {
  upload_date: string
  total_orders: number
  total_quantity: number
}

type ViewType = 'daily' | 'weekly' | 'monthly'

export default function ManufacturerShipmentPage() {
  const [file, setFile] = useState<File | null>(null)
  const [parsedData, setParsedData] = useState<ManufacturerShipmentData[]>([])
  const [isUploading, setIsUploading] = useState(false)
  const [todayStats, setTodayStats] = useState<DailyStats | null>(null)
  const [weekStats, setWeekStats] = useState<DailyStats | null>(null)
  const [monthStats, setMonthStats] = useState<DailyStats | null>(null)
  const [recentDates, setRecentDates] = useState<DailyStats[]>([])
  const [viewType, setViewType] = useState<ViewType>('daily')
  const [manualDate, setManualDate] = useState<string>('')
  const [availableSheets, setAvailableSheets] = useState<string[]>([])
  const [selectedSheet, setSelectedSheet] = useState<string>('')
  const [workbookData, setWorkbookData] = useState<XLSX.WorkBook | null>(null)

  // 오늘 날짜
  const today = new Date().toISOString().split('T')[0]
  const currentMonth = new Date().getMonth() + 1

  // 이번 주 월요일
  const getThisMonday = () => {
    const date = new Date()
    const day = date.getDay()
    const diff = date.getDate() - day + (day === 0 ? -6 : 1)
    return new Date(date.setDate(diff)).toISOString().split('T')[0]
  }

  // 이번 달 1일
  const getThisMonthStart = () => {
    const date = new Date()
    return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-01`
  }

  // 통계 불러오기
  useEffect(() => {
    fetchStats()
  }, [])

  // 엑셀 날짜 컬럼에서 날짜 추출 (1.02. → 2026-01-02)
  const extractDateFromExcel = (dateStr: string): string | null => {
    try {
      if (!dateStr) return null

      const trimmed = String(dateStr).trim().replace(/\.$/, '') // 끝의 마침표 제거
      const parts = trimmed.split('.')

      if (parts.length < 2) return null

      const month = parseInt(parts[0])
      const day = parseInt(parts[1])

      // 유효한 날짜인지 확인
      if (month < 1 || month > 12 || day < 1 || day > 31) {
        console.warn('유효하지 않은 날짜:', dateStr)
        return null
      }

      // 2026년 기준
      const year = 2026
      return `${year}-${String(month).padStart(2, '0')}-${String(day).padStart(2, '0')}`
    } catch (error) {
      console.error('엑셀 날짜 추출 실패:', dateStr, error)
      return null
    }
  }

  // 주문번호에서 날짜 추출 (202601016740864 → 2026-01-01)
  const extractDateFromOrderNumber = (orderNumber: string): string | null => {
    try {
      const orderStr = String(orderNumber).trim()

      // 주문번호가 8자리 이상의 숫자로 시작하는지 확인
      if (!/^\d{8}/.test(orderStr)) {
        console.warn('잘못된 주문번호 형식:', orderNumber)
        return null
      }

      // 첫 8자리 추출 (YYYYMMDD)
      const dateStr = orderStr.substring(0, 8)
      const year = parseInt(dateStr.substring(0, 4))
      const month = parseInt(dateStr.substring(4, 6))
      const day = parseInt(dateStr.substring(6, 8))

      // 유효한 날짜인지 확인
      if (year < 2020 || year > 2030 || month < 1 || month > 12 || day < 1 || day > 31) {
        console.warn('유효하지 않은 날짜:', dateStr)
        return null
      }

      return `${year}-${String(month).padStart(2, '0')}-${String(day).padStart(2, '0')}`
    } catch (error) {
      console.error('날짜 추출 실패:', orderNumber, error)
      return null
    }
  }

  // 날짜 추출 (엑셀 날짜 우선, 없으면 주문번호에서)
  const extractDate = (item: ManufacturerShipmentData): string | null => {
    // 1. 엑셀 날짜 컬럼 우선
    if (item.date_from_excel) {
      const dateFromExcel = extractDateFromExcel(item.date_from_excel)
      if (dateFromExcel) return dateFromExcel
    }

    // 2. 엑셀 날짜 없으면 주문번호에서 추출
    return extractDateFromOrderNumber(item.order_number)
  }

  const fetchStats = async () => {
    try {
      // raw 테이블에서 직접 집계 (뷰의 total_orders 버그 우회)
      // 택배건수 = 송장번호 있으면 송장번호, 없으면 주문번호 기준 고유 수
      // 상품수량 = quantity 합계
      const pageSize = 1000
      let allRows: { upload_date: string; order_number: string; tracking_no: string; quantity: number }[] = []
      let from = 0
      while (true) {
        const { data: pageData, error: pageError } = await supabase
          .from('manufacturer_shipment_data')
          .select('upload_date, order_number, tracking_no, quantity')
          .order('upload_date', { ascending: false })
          .range(from, from + pageSize - 1)

import { supabase } from '@/lib/supabase'
import B2BCompaniesClient from '@/components/B2BCompaniesClient'
import { sortBarcodesByInventoryOrder } from '@/lib/barcode-order'

export const dynamic = 'force-dynamic'
export const revalidate = 0

export default async function B2BCompaniesPage() {
  // SKU 데이터 가져오기 (세트 제외, 단품만)
  const { data: skuData } = await supabase
    .from('product_sku')
    .select('barcode, sku_name, product_category, selling_price, is_set')
    .eq('is_set', false)

  // 바코드 정보 맵 생성
  const barcodeInfo: Record<string, { productName: string }> = {}
  const productMap: Record<string, any> = {}

  skuData?.forEach(item => {
    barcodeInfo[item.barcode] = { productName: item.sku_name }
    productMap[item.barcode] = {
      barcode: item.barcode,
      name: item.sku_name,
      category: item.product_category,
      price: item.selling_price,
    }
  })

  // 재고현황 순서로 정렬 (제품별 일별 현황과 동일한 순서)
  const sortedBarcodes = sortBarcodesByInventoryOrder(
    Object.keys(barcodeInfo),
    barcodeInfo
  )

  // 정렬된 순서로 제품 배열 생성
  const products = sortedBarcodes.map(barcode => productMap[barcode])

  return <B2BCompaniesClient products={products} />
}

