const updateStatus = async (id: string, newStatus: string) => {
  const company = companies.find(c => c.id === id)

  // 완료로 변경 시 아웃바운딩에 자동 추가
  if (newStatus === '완료' && company) {
    const alreadyExists = await existsOutboundByPhone(company.phone)
    if (!alreadyExists) {
      await insertOutbound({
        name: company.name,
        contact: company.contact,
        phone: company.phone,
        email: company.email,
        industry: '',
        status: '미연락',
        notes: `거래 완료일: ${new Date().toISOString().split('T')[0]}`,
        createdAt: new Date().toISOString().split('T')[0],
        sourceType: 'completed',
      })
      alert(`✅ "${company.name}" 업체가 아웃바운딩 목록에 추가되었습니다. (거래 완료)`)
    }
  }

  await updateCompanyRow(id, { status: newStatus })
  setCompanies(companies.map(c => c.id === id ? { ...c, status: newStatus } : c))
}


const deleteCompany = async (id: string) => {
  if (confirm('이 업체를 삭제하시겠습니까?')) {
    const ok = await deleteCompanyRow(id)
    if (ok) {
      setCompanies(companies.filter(c => c.id !== id))
    } else {
      alert('삭제 실패. 다시 시도해주세요.')
    }
  }
}

const updateCompany = async (id: string, updates: Partial<Company>) => {
  setCompanies(companies.map(c => c.id === id ? { ...c, ...updates } : c))
  await updateCompanyRow(id, updates)
}

const moveToOutbound = async (company: Company) => {
  if (!confirm(`"${company.name}" 업체를 아웃바운딩으로 이동하시겠습니까?\n(견적 전달 후 무응답/보류)`)) {
    return
  }

  const alreadyExists = await existsOutboundByPhone(company.phone)
  if (alreadyExists) {
    alert('이미 아웃바운딩에 등록된 업체입니다.')
    return
  }

  await insertOutbound({
    name: company.name,
    contact: company.contact,
    phone: company.phone,
    email: company.email,
    industry: '',
    status: '미연락',
    notes: `견적 전달일: ${new Date().toISOString().split('T')[0]} (무응답/보류)`,
    createdAt: new Date().toISOString().split('T')[0],
    sourceType: 'pending',
  })

  alert(`✅ "${company.name}" 업체가 아웃바운딩 목록에 추가되었습니다. (팔로우업)`)
}

const toggleProgressChecklist = async (id: string, key: 'paymentConfirmed' | 'manufacturerOrdered') => {
  const target = companies.find(c => c.id === id)
  if (!target) return
  const newChecklist = {
    ...target.progressChecklist!,
    [key]: !target.progressChecklist![key],
  }
  setCompanies(companies.map(c =>
    c.id === id ? { ...c, progressChecklist: newChecklist } : c
  ))
  await updateCompanyRow(id, { progressChecklist: newChecklist })

