  if (!confirm(`"${company.name}" 업체를 진행업체로 이동하시겠습니까?`)) {
    return
  }

  // 진행업체에 추가
  await insertCompany({
    name: company.name,
    businessNumber: '',
    businessLicenseReceived: false,
    contact: company.contact,
    phone: company.phone,
    email: company.email,
    products: '',
    quantity: '',
    dueDate: '',
    address: '',
    deliveryCondition: '',
    budget: '',
    purpose: '',
    taxInvoiceType: '',
    estimateDelivered: false,
    status: '문의접수',
    createdAt: new Date().toISOString().split('T')[0],
    notes: `재거래 (아웃바운딩에서 이동)`,
    progressChecklist: {
      paymentConfirmed: false,
      manufacturerOrdered: false,
    },
    estimatePrice: '',
    finalPrice: '',
  })

  // 아웃바운딩에서 상태 '완료'로 변경
  await updateStatus(company.id, '완료')

  alert(`✅ "${company.name}" 업체가 진행업체로 이동되었습니다.`)
}

